SELECT ndg.*, njs.*, nju.*, nds.*, nda.*, ndfg.*, ng.* FROM ( SELECT ndg.nx_distributer_goods_id FROM nx_distributer_goods AS ndg LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id
AND ndfg.nx_dfg_fathers_father_id = #{grandId}
AND ndg.nx_dg_goods_is_hidden = #{isHidden}
AND ndg.nx_dg_purchase_auto = #{goodsType}
ORDER BY ndfg.nx_dfg_father_goods_sort, ndg.nx_dg_goods_sort, ndg.nx_dg_goods_sons_sort LIMIT #{offset}, #{limit} ) AS page
JOIN nx_distributer_goods AS ndg ON ndg.nx_distributer_goods_id = page.nx_distributer_goods_id LEFT JOIN nx_goods AS ng on ng.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_jrdh_supplier AS njs ON ndg.nx_dg_supplier_id = njs.nx_jrdh_supplier_id LEFT JOIN nx_jrdh_user AS nju ON nju.nx_jrdh_user_id = njs.nx_jrdhs_user_id LEFT JOIN nx_distributer_standard AS nds ON nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_alias AS nda ON nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id
ORDER BY ndfg.nx_dfg_father_goods_sort, ndg.nx_dg_goods_sort, ndg.nx_dg_goods_sons_sort

