SELECT ndg.*, ng.*, ndfg.*, ndo.*, gdg.*, gddg.*, gds.*, nds.*, nda.* FROM ( SELECT ndg.nx_distributer_goods_id FROM nx_distributer_goods AS ndg LEFT JOIN nx_goods AS ng ON ng.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = ndg.nx_dg_nx_goods_id AND gdg.gb_dg_distributer_id = #{gbDisId} LEFT JOIN gb_department_dis_goods AS gddg ON gddg.gb_DDG_department_id = #{gbDepId} AND gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id
AND ndfg.nx_dfg_fathers_father_id = #{grandId}
AND ndg.nx_dg_goods_is_hidden = #{isHidden}
ORDER BY ndfg.nx_dfg_father_goods_sort, ndg.nx_dg_goods_sort, ndg.nx_dg_goods_sons_sort, ndg.nx_distributer_goods_id LIMIT #{offset}, #{limit} ) AS limited_goods LEFT JOIN nx_distributer_goods AS ndg ON ndg.nx_distributer_goods_id = limited_goods.nx_distributer_goods_id LEFT JOIN nx_goods AS ng ON ng.nx_goods_id = ndg.nx_dg_nx_goods_id LEFT JOIN nx_distributer_father_goods AS ndfg ON ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = ndg.nx_dg_nx_goods_id AND gdg.gb_dg_distributer_id = #{gbDisId} LEFT JOIN gb_department_dis_goods AS gddg ON gddg.gb_DDG_department_id = #{gbDepId} AND gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id LEFT JOIN gb_department_goods_stock AS gds ON gds.gb_dgs_gb_dep_dis_goods_id = gddg.gb_department_dis_goods_id LEFT JOIN nx_distributer_standard AS nds ON nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_distributer_alias AS nda ON nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id LEFT JOIN nx_department_orders AS ndo ON ndo.nx_DO_dis_goods_id = ndg.nx_distributer_goods_id AND ndo.nx_DO_status < 3 AND ndo.nx_DO_gb_department_id = #{gbDepId}

