and nddg.nx_DDG_department_id = #{depId}
left join nx_distributer_standard as nds on nds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id
left join nx_distributer_alias as nda on nda.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id



        and nx_dg_distributer_id = #{disId}


        AND nx_dg_goods_name like   CONCAT('%', #{searchStr}, '%')



        and nx_dg_goods_standardname = #{standard}




        and nx_dg_nx_goods_id is not null

select *
from nx_distributer_goods as dg

         left join nx_distributer_standard as ds on ds.nx_DS_dis_goods_id = dg.nx_distributer_goods_id
         left join nx_distributer_alias as da on da.nx_DA_dis_goods_id = dg.nx_distributer_goods_id
         left join nx_department_orders as dor on dor.nx_DO_dis_goods_id = dg.nx_distributer_goods_id
    and dor.nx_DO_status < 3 and dor.nx_DO_department_id = #{depId}
         left join nx_department_dis_goods as nddg on nddg.nx_DDG_dis_goods_id = dg.nx_distributer_goods_id
    and nddg.nx_DDG_department_id = #{depId}
         left join nx_department_user as du on du.nx_department_user_id = dor.nx_DO_order_user_id
where (nx_dg_goods_name =   #{searchStr}

    or da.nx_da_alias_name = #{searchStr}
    or nx_dg_goods_pinyin = #{searchPinyin}
    or da.nx_DA_alias_pinyin =  #{searchPinyin}
    or da.nx_DA_alias_py = #{searchPinyin}
    or nx_dg_goods_py =  #{searchPinyin}
    )
  and
    nx_dg_distributer_id = #{disId}
order by dg.nx_dg_nx_great_grand_id, dg.nx_dg_goods_sort, dg.nx_dg_goods_sons_sort

